import{t as n,j as e,E as a,aQ as c,aS as i}from"./index-DhMUny8g.js";const l={privacy:{title:"Privacy Policy",content:["Effective Date: April 1, 2026",'OsirisCare ("we", "us", "our") operates the OsirisCare compliance monitoring platform. This Privacy Policy describes how we collect, use, and protect information when you use our services.',"Information We Collect: We collect infrastructure telemetry data (system configuration state, compliance scan results, remediation activity logs) from appliances deployed at your facilities. This data is used to provide compliance monitoring and issue detection services. All data transmitted from appliances is scrubbed of Protected Health Information (PHI) at the appliance level before reaching our servers. Our central infrastructure is designed to operate under a PHI-scrubbed architecture.","How We Use Information: Infrastructure telemetry is used solely to provide compliance monitoring, generate evidence bundles, produce compliance reports, and operate the healing pipeline. We do not sell, rent, or share your data with third parties except as required to provide the service or as required by law.","Data Security: All evidence bundles are cryptographically signed (Ed25519), hash-chained (SHA-256), and blockchain-timestamped (OpenTimestamps). Data in transit is encrypted via TLS. Data at rest is encrypted. Multi-tenant isolation is enforced via row-level security across all database tables.","Data Retention: Compliance evidence is retained for the duration of your subscription plus 7 years (matching HIPAA record retention requirements). You may request data export or deletion at any time.","Your Rights: You may access, correct, or delete your data by contacting us. You may request a full data export at any time. There is no lock-in period.","Contact: legal@osiriscare.net"]},terms:{title:"Terms of Service",content:["Effective Date: April 1, 2026","These Terms of Service govern your use of the OsirisCare compliance monitoring platform.","Service Description: OsirisCare provides automated compliance monitoring tools including continuous compliance scanning, evidence capture, auto-healing, and compliance reporting for healthcare organizations. The service operates via on-premise appliances that monitor your infrastructure and report to our central management platform.","Your Responsibilities: You are solely responsible for your organization's compliance program, policies, regulatory obligations, and remediation decisions. OsirisCare is a monitoring and automation tool that supports your compliance efforts — it does not replace your compliance program, provide legal advice, or guarantee regulatory compliance.","Operator Authorization: All remediation actions performed by the platform are governed by rules that your designated operators configure and approve. L1 deterministic healing operates according to pre-approved runbooks. L2 intelligent healing operates within parameters you set. L3 escalations always require human authorization.","Availability: We target 99.9% uptime for the central management platform. On-premise appliances operate independently and continue scanning during connectivity interruptions. Evidence is cached locally and synchronized when connectivity is restored.","Limitation of Liability: OsirisCare's total liability is limited to the fees paid in the 12 months preceding the claim. We are not liable for regulatory penalties, audit findings, or compliance failures, as compliance responsibility rests with your organization.","Termination: Either party may terminate with 30 days written notice. Upon termination, you may request a full data export. On-premise appliances are returned or decommissioned.","Contact: legal@osiriscare.net"]},baa:{title:"Business Associate Agreement",content:["OsirisCare executes Business Associate Agreements (BAAs) with all healthcare clients as required by HIPAA.","Architecture Note: OsirisCare's platform is designed so that Protected Health Information (PHI) is scrubbed at the appliance level before transmission to central servers. All data is scrubbed of PHI at the appliance level using 14 pattern-matching rules before transmission to our central servers. Our central infrastructure is engineered to be PHI-scrubbed architecture.","Despite this PHI-scrubbed architecture, we execute BAAs as a matter of best practice and to provide our clients with the contractual protections they expect from any vendor operating in healthcare IT.","BAA Coverage: Our BAA covers the operation of on-premise monitoring appliances, central management infrastructure, evidence storage, and compliance reporting services. It includes standard provisions for breach notification, data safeguards, permitted uses, and termination.","To request a BAA or discuss specific terms, contact us at administrator@osiriscare.net or schedule a call through our website.","Note: The availability of a BAA does not alter the fundamental responsibility structure — your organization remains the Covered Entity responsible for its HIPAA compliance program. OsirisCare operates as a Business Associate providing compliance monitoring tools."]}},m=()=>{const{page:r}=n(),t=l[r||""];return t?e.jsxs("div",{className:"min-h-screen bg-white",style:{fontFamily:"'DM Sans', 'Helvetica Neue', system-ui, sans-serif"},children:[e.jsx("style",{children:"@import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600&display=swap');"}),e.jsx("nav",{className:"border-b border-slate-100 bg-white",children:e.jsxs("div",{className:"max-w-3xl mx-auto px-6 h-16 flex items-center justify-between",children:[e.jsxs(a,{to:"/",className:"flex items-center gap-3",children:[e.jsx("div",{className:"w-8 h-8 rounded-lg flex items-center justify-center",style:{background:"linear-gradient(135deg, #14A89E 0%, #0d9488 100%)"},children:e.jsx(c,{className:"w-4 h-4",color:"white"})}),e.jsx("span",{className:"text-base font-semibold text-slate-900",children:i.name})]}),e.jsx(a,{to:"/",className:"text-sm text-slate-500 hover:text-slate-900",children:"Back to home"})]})}),e.jsxs("main",{className:"max-w-3xl mx-auto px-6 py-16",children:[e.jsx("h1",{className:"text-3xl font-bold text-slate-900 mb-8",children:t.title}),t.content.map((s,o)=>e.jsx("p",{className:"text-sm text-slate-600 leading-relaxed mb-6",children:s},o)),e.jsx("div",{className:"border-t border-slate-100 pt-8 mt-12",children:e.jsxs("p",{className:"text-xs text-slate-400",children:["© ",new Date().getFullYear()," ",i.name,". All rights reserved."]})})]})]}):e.jsx("div",{className:"min-h-screen bg-white flex items-center justify-center",children:e.jsxs("div",{className:"text-center",children:[e.jsx("p",{className:"text-slate-500",children:"Page not found"}),e.jsx(a,{to:"/",className:"text-teal-600 hover:underline mt-2 inline-block",children:"Back to home"})]})})};export{m as Legal,m as default};
